    RelatedTicketsComponent.prototype.getNamedEntities = function () {
        var _this = this;
        if (this.namedEntities.length == 0) {
            this.httpClient.get('/api/getNER/' + this.customerId + "/" + this.dataToTakeAsInput['DatasetID'] + "/" + this.dataToTakeAsInput['IncidentNumber'])
                .subscribe(function (data) {
                _this.namedEntities = data;
                if (_this.namedEntities.length > 0) {
                    _this.EntityEnabled = true;
                }
            }, function (err) {
                console.log(err);
                throw "";
            });
        }
    };
    RelatedTicketsComponent.prototype.entityValueToUpdate = function (event, id) {
        var _this = this;
        var newEntities = ((event.target.textContent).trim()).split(',');
        this.namedEntities[id]['Value'] = [];
        event.target.textContent = '';
        newEntities.forEach(function (entity) {
            if (entity.trim() != '') {
                _this.namedEntities[id]['Value'].push(entity.trim());
                event.target.textContent = event.target.textContent + entity.trim() + ', ';
            }
        });
    };
    RelatedTicketsComponent.prototype.updateEntityValues = function () {
        var _this = this;
        this.httpClient.put('api/updateNER/' + this.customerId + '/' + this.dataToTakeAsInput['DatasetID'] + '/' + this.dataToTakeAsInput['IncidentNumber'], this.namedEntities, { 'responseType': 'text' })
            .subscribe(function (msg) {
            if (msg == 'success') {
                console.log('Added/Updated new Entity Values!');
                _this.getNamedEntities();
            }
            else {
                console.warn('Could not Add/Update new Entity Values! failure resp from api');
            }
        }, function (err) {
            console.error(err);
        });
    };
    RelatedTicketsComponent.prototype.getPredictedTickets = function (custID) {
        var _this = this;
        //this.loading = true;
        this.incidentTicketsData = [];
        this.httpClient.get('/api/predictedTickets/' + custID + "/" + this.dataToTakeAsInput['DatasetID']).subscribe(function (data) {
            console.log('in getPredictedTickets');
            _this.predictedTicketsData = data;
            _this.getAllFields(custID);
            console.log(_this.predictedTicketsData);
            _this.predictedTicketsData.forEach(function (ticket) {
                ticket['Selected'] = false;
                if (ticket["number"] === _this.dataToTakeAsInput['IncidentNumber']) {
                    _this.showApprove = true;
                    _this.rawTicketData.forEach(function (field, index) {
                        Object.keys(field).forEach(function (key) {
                            //console.log("key : " + key + " - value : " + field[key]);
                            ticket[key] = field[key];
                        });
                    });
                    _this.incidentTicketsData.push(ticket);
                }
            });
            //this.getPredictedFields(custID);
        }, function (err) {
            //this.loading = false;
            console.log(err);
            throw "";
        });
        //this.loading = false;
    };
    RelatedTicketsComponent.prototype.applyFilter = function (filterValue) {
        this.dataSource.filter = filterValue.trim().toLowerCase();
        if (this.dataSource.paginator) {
            this.dataSource.paginator.firstPage();
        }
    };
